@@ -1,15 +1,15 @@
 module mux_8to1(
   input [7:0] data_in,
   input [2:0] select,
   output logic out
 );
   assign out = data_in[select];
 endmodule

 module testbench;
   logic [7:0] input_data;
   logic [2:0] sel;
   logic mux_out;
